/**
 * adversarialSafetyQA.ts
 *
 * PURPOSE: Stress-test the fail-safe property of the Aivana readiness engine.
 *
 * This is NOT a score-accuracy test. It tests a single safety invariant:
 *
 *   "For any input whose ICD-10 code is not in the engine's requirement map,
 *    the engine MUST return needsManualReview=true AND score ≤ 40."
 *
 * The cases below are deliberately crafted — NOT generated by Gemini — so they
 * have zero DNA overlap with the cases that were used to design the fix.
 *
 * Categories tested:
 *   A. Genuinely unmapped but valid ICD-10 codes (rare/obscure conditions)
 *   B. Edge-case boundary codes (adjacent to mapped prefixes)
 *   C. Malformed / invalid code strings
 *   D. Clinically severe but unmapped conditions (the most dangerous category)
 *   E. Empty / null / missing diagnosis inputs
 *   F. Text-only diagnoses with no ICD-10 code
 *   G. Codes that LOOK like they might match a mapped prefix but don't
 *
 * A "slip-through" bug = any case where needsManualReview is false OR score > 40
 * while the input is not in the mapped set.
 */

import { computeReadiness } from '../../utils/readinessScore';
import { isIcdMapped } from '../../utils/documentRequirements';
import { PreAuthRecord } from '../../components/PreAuthWizard/types';

// ─── helpers ──────────────────────────────────────────────────────────────────

const SAFE_SCORE_CEILING = 40; // max score allowed for an unmapped condition
const PASS = '✅ PASS';
const FAIL = '❌ FAIL  ← SLIP-THROUGH BUG';

interface AdversarialCase {
    label: string;
    category: string;
    icd10Code: string;
    diagnosisText: string;
    expectMapped: boolean; // true = we expect the engine to KNOW this code
}

// Minimal fully-populated record that removes all OTHER scoring penalties
// (so the only deduction that should fire is the unmapped-condition penalty)
