// ─── main runner ──────────────────────────────────────────────────────────────

interface TestResult {
    label: string;
    category: string;
    icd10Code: string;
    expectMapped: boolean;
    actualMapped: boolean;
    score: number;
    needsManualReview: boolean;
    passed: boolean;
    failReason?: string;
}

function runAdversarialBatch(): void {
    console.log('\n');
    console.log('═'.repeat(90));
    console.log('  AIVANA — ADVERSARIAL SAFETY QA BATCH');
    console.log('  Testing: "Does every unmapped input fail safe to needsManualReview?"');
    console.log('═'.repeat(90));
    console.log('');
    console.log('  SAFETY INVARIANT: unmapped ICD → needsManualReview=true AND score ≤ 40');
    console.log('  A "slip-through" = any case where either property is violated.');
    console.log('');

    const results: TestResult[] = [];
    let slipThroughs = 0;

    for (const tc of cases) {
        const record = buildFullRecord(tc.icd10Code, tc.diagnosisText);
        const result = computeReadiness(record, null);
        const actualMapped = isIcdMapped(tc.icd10Code || tc.diagnosisText);

        let passed = true;
        let failReason: string | undefined;

        if (!tc.expectMapped) {
            // Safety invariant check — unmapped inputs MUST fail safe
            if (result.needsManualReview === false) {
                passed = false;
                failReason = `needsManualReview=false (SLIP-THROUGH). Score=${result.score}`;
            } else if (result.score > SAFE_SCORE_CEILING) {
                passed = false;
                failReason = `score=${result.score} > ceiling of ${SAFE_SCORE_CEILING} despite unmapped condition`;
            }
        } else {
            // Mapped inputs should NOT be flagged for manual review
            if (result.needsManualReview === true) {
                passed = false;
                failReason = `needsManualReview=true but this code IS mapped (false positive)`;
            }
        }

        if (!passed) slipThroughs++;

        results.push({
            label: tc.label,
            category: tc.category,
            icd10Code: tc.icd10Code || '(empty)',
            expectMapped: tc.expectMapped,
            actualMapped,
            score: result.score,
            needsManualReview: result.needsManualReview ?? false,
            passed,
            failReason,
        });
    }

    // ── Print results table ────────────────────────────────────────────────────
    const categoryGroups = ['A', 'B', 'C', 'D', 'E', 'F', 'G'];
    const categoryNames: Record<string, string> = {
        A: 'Valid but genuinely unmapped ICD-10 codes',
        B: 'Boundary codes — adjacent to mapped prefixes',
        C: 'Malformed / invalid code strings',
        D: 'Clinically severe but unmapped (highest risk)',
        E: 'Empty / null-like diagnosis inputs',
        F: 'Text-only diagnoses with no ICD-10 code',
        G: 'Codes that prefix-match a mapped code (should PASS scoring)',
    };

    for (const cat of categoryGroups) {
        const group = results.filter(r => r.category === cat);
        if (!group.length) continue;

        console.log(`\n  ── Category ${cat}: ${categoryNames[cat]} ──`);
        console.log(`  ${'Label'.padEnd(40)} ${'Code'.padEnd(22)} ${'Mapped?'.padEnd(10)} ${'Score'.padEnd(8)} ${'Review?'.padEnd(10)} Result`);
        console.log(`  ${'-'.repeat(110)}`);

        for (const r of group) {
            const mappedStr = r.actualMapped ? 'YES' : 'NO';
            const reviewStr = r.needsManualReview ? 'YES' : 'NO';
            const resultStr = r.passed ? PASS : `${FAIL}`;
            console.log(
                `  ${r.label.padEnd(40)} ${r.icd10Code.padEnd(22)} ${mappedStr.padEnd(10)} ${String(r.score).padEnd(8)} ${reviewStr.padEnd(10)} ${resultStr}`
            );
            if (!r.passed) {
                console.log(`    ↳ Reason: ${r.failReason}`);
            }
        }
    }

    // ── Summary ───────────────────────────────────────────────────────────────
    const total = results.length;
    const passed = results.filter(r => r.passed).length;
    const failed = total - passed;

    console.log('\n');
    console.log('═'.repeat(90));
    console.log(`  ADVERSARIAL SAFETY QA SUMMARY`);
    console.log('═'.repeat(90));
    console.log(`  Total test cases   : ${total}`);
    console.log(`  Passed (safe)      : ${passed}`);
    console.log(`  Slip-throughs BUGS : ${failed}`);
    console.log(`  Safety rate        : ${((passed / total) * 100).toFixed(1)}%`);
    console.log('─'.repeat(90));

    if (failed === 0) {
        console.log('');
        console.log('  🛡️  ALL CASES FAIL SAFE. Safety invariant is VERIFIED.');
        console.log('     The engine correctly refuses to auto-score every unmapped input.');
        console.log('     It is safe to proceed to clinically-validated map expansion.');
    } else {
        console.log('');
        console.log(`  🚨 ${failed} SLIP-THROUGH BUG(S) DETECTED.`);
        console.log('     DO NOT expand the ICD-10 map until these are fixed.');
        console.log('     Each slip-through means the engine is confidently wrong on real patients.');
        console.log('');
        // Exit with non-zero for CI
        process.exit(1);
    }
    console.log('═'.repeat(90));
    console.log('');
}

runAdversarialBatch();
